								SetAnchor(false, v)
								AddMesh(v)
								Resize(v, Vector3.new(100, 100, 100), v.CFrame)
								MeshResize(v, Vector3.new(4, 4, 4))
								SetMesh(v, "5038530279") -- Here put it A custom mesh
