function GetPartsFromSelection(Selection)

	local Parts = {}


	for _, Descendant in pairs(Selection:GetDescendants()) do

		if Descendant:IsA 'BasePart' and Descendant.Name ~= "Terrain" and Descendant.Name ~= "HD shitz" then

			Parts[#Parts + 1] = Descendant

		end

	end


	-- Return parts

	return Parts

end

