button.MouseButton1Down:connect(function()
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local Players = game:GetService("Players")

local player = Players.LocalPlayer

local char = player.Character or player.CharacterAdded:Wait()

local backpack = player.Backpack

local function getf3x()

    for _, v in ipairs(backpack:GetChildren()) do

        if v:FindFirstChild("SyncAPI") then

            return v

        end

    end

    for _, v in ipairs(char:GetChildren()) do

        if v:FindFirstChild("SyncAPI") then

            return v

        end

    end

end

local f3x = getf3x()

if not f3x then

    warn("you dont have f3x skid")

    return

end

local sync = f3x.SyncAPI.ServerEndpoint

local destination = workspace

local function f3xbuildpart(fake_part)

    local partType =

        fake_part:IsA("WedgePart") and "Wedge" or

        fake_part:IsA("Seat") and "Seat" or

        fake_part:IsA("VehicleSeat") and "VehicleSeat" or

        fake_part:IsA("TrussPart") and "Truss" or

        fake_part:IsA("SpawnLocation") and "Spawn" or

        fake_part.Shape == Enum.PartType.Ball and "Ball" or

        fake_part.Shape == Enum.PartType.Cylinder and "Cylinder" or

        "Normal"

    local created = sync:InvokeServer("CreatePart", partType, fake_part.CFrame, destination)

    if not created then return end

    sync:InvokeServer("SyncResize", {

        { Part = created, CFrame = created.CFrame, Size = fake_part.Size }

    })

    sync:InvokeServer("SyncColor", {

        { Part = created, Color = fake_part.Color, UnionColoring = true }

    })

    sync:InvokeServer("SyncMaterial", {

        { Part = created, Material = fake_part.Material }

    })

    sync:InvokeServer("SyncCollision", {

        { Part = created, CanCollide = fake_part.CanCollide }

    })

    if fake_part.Transparency > 0 then

        sync:InvokeServer("SyncMaterial", {

            { Part = created, Transparency = fake_part.Transparency }

        })

    end

    local tex = fake_part:FindFirstChildOfClass("Texture")

    if tex then

        sync:InvokeServer("CreateTextures", {

            { Part = created, Face = tex.Face, TextureType = "Texture" }

        })

        sync:InvokeServer("SyncTexture", {

            {

                Part = created,

                Face = tex.Face,

                TextureType = "Texture",

                Texture = tex.Texture,

                StudsPerTileU = tex.StudsPerTileU,

                StudsPerTileV = tex.StudsPerTileV,

                Transparency = tex.Transparency

            }

        })

    end

    local decal = fake_part:FindFirstChildOfClass("Decal")

    if decal then

        sync:InvokeServer("CreateTextures", {

            { Part = created, Face = decal.Face, TextureType = "Decal" }

        })

        sync:InvokeServer("SyncTexture", {

            {

                Part = created,

                Face = decal.Face,

                TextureType = "Decal",

                Texture = decal.Texture,

                Transparency = decal.Transparency

            }

        })

    end

    local mesh = fake_part:FindFirstChildOfClass("SpecialMesh")

    if mesh then

        sync:InvokeServer("CreateMeshes", { { Part = created } })

        sync:InvokeServer("SyncMesh", {

            {

                Part = created,

                MeshId = mesh.MeshId,

                TextureId = mesh.TextureId,

                Scale = mesh.Scale

            }

        })

    end

end

