					llcf = llc0 * CFrame.new(0, .3 - -math.cos(angle) * .3, -.05 - math.sin(angle) * 0.25) * CFrame.Angles(-math.pi/18 + math.sin(angle) * 1.3, 0, -math.rad(.5))	
				end	

				rm.C0 = clerp(rm.C0, rscf, speed)	
				lm.C0 = clerp(lm.C0, lscf, speed)	
