button.MouseButton1Down:connect(function()
local ReplicatedStorage = game:GetService("ReplicatedStorage")

    local RequestCommandSilent = ReplicatedStorage:WaitForChild("HDAdminHDClient").Signals.RequestCommandSilent

-- Raining tacos, credits to original author: ItsKittyyyGD

local player = game.Players.LocalPlayer

local char = player.Character or player.CharacterAdded:Wait()

local tool

for i, v in player:GetDescendants() do

    if v.Name == "SyncAPI" then

        tool = v.Parent

    end

end

for i, v in game.ReplicatedStorage:GetDescendants() do

    if v.Name == "SyncAPI" then

        tool = v.Parent

    end

end

local remote = tool.SyncAPI.ServerEndpoint

function _(args)

    remote:InvokeServer(unpack(args))

end

function SetCollision(part, boolean)

    local args = {

        [1] = "SyncCollision",

        [2] = {

            [1] = {

                ["Part"] = part,

                ["CanCollide"] = boolean

            }

        }

    }

    _(args)

end

		function MovePart(part,cf)			local args = {

				[1] = "SyncMove",

				[2] = {

					[1] = {

						["Part"] = part,

						["CFrame"] = cf

					}

				}

			}

			_(args)

		end

function SetAnchor(boolean, part)

    local args = {

        [1] = "SyncAnchor",

        [2] = {

            [1] = {

                ["Part"] = part,

                ["Anchored"] = boolean

            }

        }

    }

    _(args)

end

function CreatePart(cf, parent)

    local args = {

        [1] = "CreatePart",

        [2] = "Normal",

        [3] = cf,

        [4] = parent

    }

    _(args)

end

function Resize(part, size, cf)

    local args = {

        [1] = "SyncResize",

        [2] = {

            [1] = {

                ["Part"] = part,

                ["CFrame"] = cf,

                ["Size"] = size

            }

        }

    }

    _(args)

end

function AddMesh(part)

    local args = {

        [1] = "CreateMeshes",

        [2] = {

            [1] = {

                ["Part"] = part

            }

        }

    }

    _(args)

end

function SetMesh(part, meshid)

    local args = {

        [1] = "SyncMesh",

        [2] = {

            [1] = {

                ["Part"] = part,

                ["MeshId"] = "rbxassetid://" .. meshid

            }

        }

    }

    _(args)

end

function SetTexture(part, texid)

    local args = {

        [1] = "SyncMesh",

        [2] = {

            [1] = {

                ["Part"] = part,

                ["TextureId"] = "rbxassetid://" .. texid

            }

        }

    }

    _(args)

end

function MeshResize(part, size)

    local args = {

        [1] = "SyncMesh",

        [2] = {

            [1] = {

                ["Part"] = part,

                ["Scale"] = size

            }

        }

    }

    _(args)

end

function SetName(part, stringg)

    local args = {

        [1] = "SetName",

        [2] = {

            [1] = workspace.Part

        },

        [3] = stringg

    }

    _(args)

end

function Sky(id)

    local hrp = char:WaitForChild("HumanoidRootPart")

    local cf = hrp.CFrame

    CreatePart(CFrame.new(cf.Position + Vector3.new(0, 6, 0)), workspace)

    for _, v in workspace:GetDescendants() do

        if v:IsA("BasePart") and v.CFrame.Position == cf.Position + Vector3.new(0, 6, 0) then

            SetAnchor(true, v)

            AddMesh(v)

            SetMesh(v, "111891702759441")

            SetTexture(v, id)

            MeshResize(v, Vector3.new(8000, 8000, 8000))

        end

    end

end

local function createRainToads()

    while true do

        wait(0.001)

        if player.Character and player.Character:FindFirstChild("Humanoid") and player.Character.Humanoid.Health > 0 then

            local hrpcf = player.Character.HumanoidRootPart.CFrame

            local x = hrpcf.x

            local z = hrpcf.z

            local randint = math.random(-600, 600)

            local randint2 = math.random(-600, 600)

            local xloc = randint + x

            local zloc = randint2 + z

            local cf = player.Character.HumanoidRootPart.CFrame.y + 800  

            spawn(function()

                local newToad = CreatePart(CFrame.new(math.floor(xloc), math.random(cf, cf + 400), math.floor(zloc)), workspace)

                for i, v in game.Workspace:GetDescendants() do

                    if v.Name == "Part" and v.Parent == workspace and v.CFrame.x == math.floor(xloc) and v.CFrame.z == math.floor(zloc) then

                        spawn(function()

                        SetName(v, "Taco")

                        end)

                        spawn(function()

                        SetAnchor(false, v)

                        end)

                        spawn(function()

                        AddMesh(v)

                        end)

                        spawn(function()

                        MeshResize(v, Vector3.new(20, 20, 20))

                        end)

                        spawn(function()

                        SetMesh(v, "14846869")

                        end)

                        spawn(function()

                        SetTexture(v, "14846834")

                        end)

                        spawn(function()

                        SetCollision(v, false)

                        end)

                        spawn(function()

                        MovePart(v, v.CFrame * CFrame.new(

    math.random(-5, 5), 

    math.random(0, 10), 

    math.random(-5, 5) 

) * CFrame.Angles(

    math.rad(math.random(10, 180)),

    math.rad(math.random(10, 180)),

    math.rad(math.random(10, 180))

))

                        end)

                        

                

                    end

                end

            end)

        else

            wait(1)

        end

    end

end

coroutine.wrap(createRainToads)()

