local function getTargetPart()

	for _, v in workspace:GetDescendants() do

		if v:IsA("BasePart") and v.Name == "pat" then

			return v

		end

	end

	return nil

end

local function getValidParts(targetPart)

	local parts = {}

	for _, v in workspace:GetDescendants() do

		if v:IsA("BasePart")

			and v:IsDescendantOf(workspace)

			and v ~= targetPart

			and v.Name ~= "Head"

			and v.Name ~= "Torso"

			and v.Name ~= "Baseplate"

			and v.Name ~= "SpawnLocation"

			and v.Size.X <= 60

			and v.Size.Z <= 60

		then

			table.insert(parts, v)

		end

	end

	return parts

end

local function movePartToward(part, targetCF)

	local dir = (targetCF.Position - part.Position).Unit

	local speed = 1

	local maxSpeed = 1000

	local acceleration = 4

	task.spawn(function()

		while speed < maxSpeed do

			speed += acceleration

			if speed > maxSpeed then speed = maxSpeed end

			task.wait(0.1)

		end

	end)

	local newCF = CFrame.new(part.Position + dir * speed)

	MovePart(part, newCF)

end

task.spawn(function()

	while true do

		local target = getTargetPart()

		if not target then task.wait(0.5) continue end

		local parts = getValidParts(target)

		if #parts == 0 then break end

		local index = 1

		while index <= #parts do

			for i = 1, 1 do

				local part = parts[index]

				index += 1

				if not part then break end

				task.spawn(function()

					while part and part:IsDescendantOf(workspace) do

						local distance = (part.Position - target.Position).Magnitude

						

						if part.Name == "HumanoidRootPart" and distance <= 14 then

							local parent = part.Parent

							if parent then

								delete(parent)

							end

							break

						elseif distance <= 10 then

							delete(part)

							break

						end

						SetAnchor(true, part)

						movePartToward(part, target.CFrame)

						task.wait(0.05)

					end

				end)

			end

			task.wait(0.3)

		end

		task.wait(1)

	end

end)
end)
